// Idempotent reaction insert: ON CONFLICT triggers a no-op UPDATE so RETURNING
// still emits the row. Without that, ON CONFLICT DO NOTHING would not return
// anything when the (message_id, reactor, emoji) tuple already existed, and
// the caller would have to follow up with a SELECT — extra round-trip for the
// common "double-tap an emoji" path.
func (q *Queries) InsertChannelMessageReaction(ctx context.Context, arg InsertChannelMessageReactionParams) (ChannelMessageReaction, error) {
	row := q.db.QueryRow(ctx, insertChannelMessageReaction,
		arg.MessageID,
		arg.ReactorType,
		arg.ReactorID,
		arg.Emoji,
	)
	var i ChannelMessageReaction
	err := row.Scan(
		&i.ID,
		&i.MessageID,
		&i.ReactorType,
		&i.ReactorID,
		&i.Emoji,
		&i.CreatedAt,
	)
	return i, err
}

